 1→import { doorOutlineOnWall } from '@/geometry/wallGeometry';
 2→
 3→export default function DoorRenderer({ doors, walls }) {
 4→  return (
 5→    <g className="doors">
 6→      {doors.map(door => {
 7→        const wall = walls.find(w => w.id === door.wallId);
 8→        if (!wall) return null;
 9→
10→        const info = doorOutlineOnWall(wall, door);
11→        const angleDeg = (info.angle * 180) / Math.PI;
12→        const flipSign = door.openDirection === 'right' ? -1 : 1;
13→
14→        return (
15→          <g key={door.id} data-id={door.id} data-type="door">
16→            {/* White rectangle to mask wall */}
17→            <polygon
18→              points={`${info.p1.x},${info.p1.y} ${info.p2.x},${info.p2.y} ${info.p3.x},${info.p3.y} ${info.p4.x},${info.p4.y}`}
19→              fill="white"
20→              stroke="none"
21→            />
22→            {/* Door swing arc */}
23→            <g transform={`translate(${info.start.x},${info.start.y}) rotate(${angleDeg})`}>
24→              {/* Door leaf line */}
25→              <line
26→                x1={0} y1={0}
27→                x2={0} y2={flipSign * -door.width}
28→                stroke="var(--color-wall-fill)"
29→                strokeWidth={2}
30→                vectorEffect="non-scaling-stroke"
31→              />
32→              {/* Arc */}
33→              <path
34→                d={`M ${door.width} 0 A ${door.width} ${door.width} 0 0 ${door.openDirection === 'left' ? 1 : 0} 0 ${flipSign * -door.width}`}
35→                fill="none"
36→                stroke="var(--color-wall-fill)"
37→                strokeWidth={1}
38→                strokeDasharray="4 3"
39→                vectorEffect="non-scaling-stroke"
40→              />
41→            </g>
42→          </g>
43→        );
44→      })}
45→    </g>
46→  );
47→}
