 8→export function useEditorTool({ activeTool, dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled, selectedId, selectedType, toolState }) {
 9→  const getFloorRef = useRef(getFloor);
10→  getFloorRef.current = getFloor;
11→
12→  const handler = useMemo(() => {
13→    const ctx = {
14→      dispatch, editorDispatch,
15→      getFloor: (...args) => getFloorRef.current(...args),
16→      activeFloorId, viewport, snapEnabled,
17→    };
18→
19→    switch (activeTool) {
20→      case TOOLS.WALL:
21→        return createWallDrawHandler(ctx);
22→      case TOOLS.SELECT:
23→        return createSelectHandler(ctx);
24→      case TOOLS.DOOR:
25→        return createDoorPlaceHandler(ctx);
26→      case TOOLS.WINDOW:
27→        return createWindowPlaceHandler(ctx);
28→      default:
29→        return null;
30→    }
31→  }, [activeTool, activeFloorId, viewport.zoom, snapEnabled]);
32→
33→  return {
34→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
35→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
36→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
37→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
38→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
39→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
40→  };
