 49→export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
 50→  if (!selectedId || !floor) return null;
 51→
 52→  if (selectedType === 'wall') {
 53→    const wall = floor.walls.find(w => w.id === selectedId);
 54→    if (!wall) return null;
 55→    return <WallSelection wall={wall} zoom={zoom} />;
 56→  }
 57→
 58→  if (selectedType === 'door') {
 59→    const door = floor.doors.find(d => d.id === selectedId);
 60→    if (!door) return null;
 61→    const wall = floor.walls.find(w => w.id === door.wallId);
 62→    if (!wall) return null;
 63→    // Highlight parent wall subtly
 64→    const outline = wallOutline(wall);
 65→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 66→    return (
 67→      <polygon
 68→        points={points}
 69→        fill="none"
 70→        stroke="var(--color-selection)"
 71→        strokeWidth={2}
 72→        strokeDasharray="6 3"
 73→        vectorEffect="non-scaling-stroke"
 74→      />
 75→    );
 76→  }
 77→
 78→  if (selectedType === 'window') {
 79→    const win = floor.windows.find(w => w.id === selectedId);
 80→    if (!win) return null;
 81→    const wall = floor.walls.find(w => w.id === win.wallId);
 82→    if (!wall) return null;
 83→    const outline = wallOutline(wall);
 84→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 85→    return (
 86→      <polygon
 87→        points={points}
 88→        fill="none"
 89→        stroke="var(--color-selection)"
 90→        strokeWidth={2}
 91→        strokeDasharray="6 3"
 92→        vectorEffect="non-scaling-stroke"
 93→      />
 94→    );
 95→  }
 96→
 97→  if (selectedType === 'room') {
 98→    const room = floor.rooms.find(r => r.id === selectedId);
 99→    if (!room?.points?.length) return null;
100→    const points = room.points.map(p => `${p.x},${p.y}`).join(' ');
101→    return (
102→      <polygon
103→        points={points}
104→        fill="none"
105→        stroke="var(--color-selection)"
106→        strokeWidth={2}
107→        strokeDasharray="6 3"
108→        vectorEffect="non-scaling-stroke"
109→      />
110→    );
111→  }
112→
113→  return null;
114→}
